 p_id=>wwv_flow_imp.id(114010849633528784530)
,p_name=>'Custom Authentication'
,p_scheme_type=>'NATIVE_CUSTOM'
,p_attribute_03=>'my_auth'
,p_attribute_05=>'N'
,p_plsql_code=>wwv_flow_string.join(wwv_flow_t_varchar2(
'FUNCTION my_auth (',
'p_username IN VARCHAR2,',
'p_password IN VARCHAR2)',
'RETURN BOOLEAN AS',
'found number := 0;',
'BEGIN',
'SELECT 1 into found FROM users',
'WHERE upper(user_name) = upper(p_username)',
'AND upper(user_password) = upper(p_password)',
'AND USER_ACTIVATED = 1;',
'RETURN TRUE;',
'EXCEPTION',
'WHEN NO_DATA_FOUND THEN',
'RETURN FALSE;',
'END;'))
,p_use_secure_cookie_yn=>'N'
,p_ras_mode=>0
,p_version_scn=>15756979128513
);
end;
